        voiceTag: "Long-context generalist",
        generationTokensPerSec: 22.7,
        prefillTokensPerSec: 74_400,
        maximCompliance: MaximScorecard(
            m1Uncertainty: .fail,
            m2Reflection:  .pass,
            m3Memory:      .pass,
            m4Refusal:     .fail,
            m5Evolution:   .pass
