        voiceTag: "Workhorse",
        generationTokensPerSec: 15.1,
        prefillTokensPerSec: 28_320,
        maximCompliance: MaximScorecard(
            m1Uncertainty: .mixed,
            m2Reflection:  .pass,
            m3Memory:      .pass,
            m4Refusal:     .standout,
            m5Evolution:   .pass
